{
  "$schema": "https://opencode.ai/config.json",
  "permission": {
    "edit": "allow",
    "bash": "allow",
    "webfetch": "allow",
    "doom_loop": "allow",
    "external_directory": "allow"
  },
  "mcp": {
    "sequential_thinking": {
      "type": "local",
      "command": [
        "npx",
        "@modelcontextprotocol/server-sequential-thinking@2025.12.18"
      ]
    },
    "mk-spec-memory": {
      "type": "local",
      "command": [
        "node",
        ".opencode/bin/mk-spec-memory-launcher.cjs"
      ],
      "environment": {
        "EMBEDDINGS_PROVIDER": "auto",
        "HF_EMBED_SERVER_URL": "unix:///tmp/mk-hf-embed/hf-embed.sock",
        "SPECKIT_IPC_SOCKET_DIR": "/tmp/mk-spec-memory",
        "SPECKIT_MAX_SECONDARY_CLIENTS": "64",
        "SPECKIT_RETRY_BATCH_SIZE": "100",
        "SPECKIT_RETRY_INTERVAL_MS": "5000",
        "SPECKIT_RETRY_QUEUE_MAX_AGE_MS": "3153600000000",
        "SPECKIT_RETRY_QUEUE_MAX_PENDING": "300000",
        "_NOTE_RECOMMENDED_SETUP": "New users: install Ollama (https://ollama.com) and run `ollama pull nomic-embed-text:v1.5`. The cascade auto-detects Ollama and persists nomic-embed-text-v1.5 (768d) as the active embedder — no API keys, all-local.",
        "_NOTE_DB": "Default DB (recommended): context-index__ollama__nomic-embed-text-v1.5__768.sqlite (auto-derived from provider+model+dim). Pull `ollama pull nomic-embed-text:v1.5` for the local-first new-user setup; hf-local with nomic-ai/nomic-embed-text-v1.5 is the zero-install Node fallback (no Python).",
        "_NOTE_PROVIDERS": "Auto cascade (ADR-014, local-first): Ollama (local) -> hf-local (pure-Node @huggingface/transformers HTTP model server, zero-install) -> OpenAI API -> Voyage API.",
        "_NOTE_EMBEDDINGS_PROVIDER": "Auto cascade (ADR-014, local-first): Ollama -> hf-local -> OpenAI -> Voyage. Set EMBEDDINGS_PROVIDER=<provider> (ollama|hf-local|openai|voyage) to force a specific tier.",
        "_NOTE_CLOUD_PROVIDERS": "Cloud tiers are explicit opt-in: add VOYAGE_API_KEY or OPENAI_API_KEY only when you want cloud embeddings; otherwise the cascade keeps everything local. Voyage is embeddings-only here; cloud rerankers (voyage/cohere) were removed in 022/013.",
        "_NOTE_GET_VOYAGE_KEY": "Get Voyage key: https://dash.voyageai.com/api-keys",
        "_NOTE_GET_OPENAI_KEY": "Get OpenAI key: https://platform.openai.com/api-keys",
        "_NOTE_HF_EMBED_SOCKET": "Shared hf-local model-server socket. Pinned identically for mk-spec-memory AND mk_skill_advisor so both consume ONE resident nomic server (single-owner via the socket-keyed respawn lock). Short /tmp path stays under the macOS sun_path 104-char limit. Do not diverge the two services.",
        "_NOTE_SOCKET": "macOS sun_path limit (104 chars): the default bridge socket path under database/daemon-ipc.sock exceeds the limit and the launcher fails with EINVAL. Pin to a short /tmp path so the multi-client bridge can bind.",
        "_NOTE_FEATURE_FLAGS": "Opt-out flags (default ON): SPECKIT_ADAPTIVE_FUSION, SPECKIT_SESSION_BOOST, SPECKIT_CAUSAL_BOOST, SPECKIT_HYDE_ACTIVE, SPECKIT_ENTITY_LINKING, SPECKIT_GRAPH_CONCEPT_ROUTING, SPECKIT_GRAPH_REFRESH_MODE=write_local. Tier 3 LLM save routing is always on (fail-open to Tier 2 on timeout).",
        "_NOTE_DAEMON_REELECTION": "Daemon re-election is on by default in the launcher code: on disposal the launcher releases the shared daemon for a live secondary to adopt instead of killing it, so concurrent sessions keep MCP transport. An unadopted released daemon is bounded by SPECKIT_LAUNCHER_IDLE_TIMEOUT_MIN. Set SPECKIT_DAEMON_REELECTION=0 to restore kill-on-disposal. See ENV_REFERENCE.md.",
        "_NOTE_RETRY_TUNING": "Bulk re-embed retry tuning: raised pending cap + max-age + faster batch/interval so a large embedding backlog drains instead of being parked as failed (defaults park excess/old pending: cap 1000, 24h age, 5-per-5min)."
      }
    },
    "mk_skill_advisor": {
      "type": "local",
      "command": [
        "node",
        ".opencode/bin/mk-skill-advisor-launcher.cjs"
      ],
      "environment": {
        "HF_EMBED_SERVER_URL": "unix:///tmp/mk-hf-embed/hf-embed.sock",
        "MK_SKILL_ADVISOR_DB_DIR": ".opencode/skills/system-skill-advisor/mcp_server/database",
        "MK_SKILL_ADVISOR_HOOK_DISABLED": "0",
        "MK_SKILL_ADVISOR_TRUST_DEFAULT": "trusted",
        "SPECKIT_ADVISOR_DOC_TRIGGERS": "true",
        "SPECKIT_IPC_SOCKET_DIR": "/tmp/mk-skill-advisor",
        "SPECKIT_MAX_SECONDARY_CLIENTS": "64",
        "_NOTE_DB": "Database lives at .opencode/skills/system-skill-advisor/mcp_server/database/skill-graph.sqlite by default; MK_SKILL_ADVISOR_DB_DIR overrides, with SYSTEM_SKILL_ADVISOR_DB_DIR as a legacy fallback (both still recognized by the launcher + handlers).",
        "_NOTE_THRESHOLDS": "Advisor confidence/uncertainty thresholds are tunable: SPECKIT_ADVISOR_CONFIDENCE_THRESHOLD (default 0.8), SPECKIT_ADVISOR_UNCERTAINTY_THRESHOLD (default 0.35). Lane weights tunable via SPECKIT_ADVISOR_LANE_WEIGHTS_JSON + SPECKIT_ADVISOR_LANE_SHADOW_WEIGHTS_JSON (partial-merge JSON, post-022/011/4b).",
        "_NOTE_DOC_TRIGGERS": "Opt-in doc-frontmatter harvest: skill_graph_scan ingests references/assets trigger_phrases into skill_docs and advisor_recommend returns matchedDocs pointers (dampened derived-lane signal). Default-off in code; enabled for this repo. Unset/false to roll back.",
        "_NOTE_TRUST_DEFAULT": "Daemon-owner trust grant for mutation tools (advisor_rebuild, skill_graph_scan, skill_graph_propagate_enhances). Callers whose _meta omits transport/trust markers default to UNTRUSTED unless this is 'trusted'. Native MCP clients (e.g. /doctor repair flows) send no _meta, so this grant keeps them working; remove it to fail-closed on every transport-absent caller. Explicit _meta trusted:false / callerAuthority:'untrusted' is always rejected.",
        "_NOTE_HF_EMBED_SOCKET": "Shared hf-local model-server socket — identical to mk-spec-memory's so both services share ONE resident nomic server. (skill-advisor only spawns it when SPECKIT_SKILL_ADVISOR_MODEL_SERVER_ENABLED=1; otherwise it just connects to mk-spec-memory's.)"
      }
    },
    "mk_code_index": {
      "type": "local",
      "command": [
        "node",
        ".opencode/bin/mk-code-index-launcher.cjs"
      ],
      "environment": {
        "SPECKIT_CODE_GRAPH_INDEX_AGENTS": "false",
        "SPECKIT_CODE_GRAPH_INDEX_COMMANDS": "false",
        "SPECKIT_CODE_GRAPH_INDEX_PLUGINS": "false",
        "SPECKIT_CODE_GRAPH_INDEX_SKILLS": "false",
        "SPECKIT_CODE_GRAPH_INDEX_SPECS": "false",
        "SPECKIT_IPC_SOCKET_DIR": "/tmp/mk-code-index",
        "SPECKIT_MAX_SECONDARY_CLIENTS": "64",
        "_NOTE_DB": "Database lives SKILL-LOCAL at .opencode/skills/system-code-graph/mcp_server/database/code-graph.sqlite by default (shared across runtimes via the .opencode/skills symlink); SPECKIT_CODE_GRAPH_DB_DIR overrides. Former shared location (.opencode/.spec-kit/code-graph/database/) is migrated back on first launcher startup.",
        "_NOTE_INDEX_DEFAULTS": "INDEX_* committed defaults are false (end-user safe). Maintainer mode: set SPECKIT_CODE_GRAPH_MAINTAINER_MODE in .env.local (gitignored) to true (forces all 5 INDEX_* to true) or to a comma-separated subset such as skills,plugins (forces only those categories); the launcher applies the selection at startup. Per-call code_graph_scan args (includeSkills, includeAgents, includeCommands, includeSpecs, includePlugins) still override env for fine-grained control.",
        "_NOTE_RESCAN_THRESHOLD": "SPECKIT_CODE_GRAPH_SELECTIVE_REINDEX_THRESHOLD (default 50) controls when the launcher switches from selective rescan to full scan. Raise to delay full-scans (faster session-boot, more drift tolerance); lower to keep the DB tighter. Post-commit hook (.opencode/scripts/git-hooks/post-commit) also invalidates the SQLite when commits exceed SPECKIT_CODE_GRAPH_POST_COMMIT_REBUILD_THRESHOLD (default 100)."
      }
    },
    "code_mode": {
      "type": "local",
      "command": [
        "/Users/michelkerkmeester/.nvm/versions/node/v24.9.0/bin/node",
        ".opencode/skills/mcp-code-mode/mcp_server/dist/index.js"
      ],
      "environment": {
        "UTCP_CONFIG_FILE": ".utcp_config.json"
      }
    }
  },
  "experimental": {
    "disable_paste_summary": true
  }
}

